public abstract class BaseRepository<T> : IRepository<T> where T : class
{
    protected readonly DbContext _dbContext;
    protected readonly DbSet<T> _dbSet;

    protected BaseRepository(DbContext dbContext)
    {
        _dbContext = dbContext;
        _dbSet = dbContext.Set<T>();
    }

    public virtual async Task<IEnumerable<T>> GetAllAsync()
    {
        return await _dbSet.ToListAsync();
    }

    public virtual async Task<T> GetByIdAsync(int id)
    {
        return await _dbSet.FindAsync(id);
    }

    public virtual async Task<IEnumerable<T>> FindByDynamicAsync(Expression<Func<T, bool>> predicate)
    {
        return await _dbSet.Where(predicate).ToListAsync();
    }

    public virtual async Task<T> FindByDynamicAsync(Expression<Func<T, bool>> predicate, bool includeTracking = false)
    {
        if (includeTracking)
        {
            return await _dbSet.Where(predicate).Include(e => e).FirstOrDefaultAsync();
        }
        else
        {
            return await _dbSet.Where(predicate).FirstOrDefaultAsync();
        }
    }
}
